666→    /** All the notes of the selected cards will be marked
667→     * If one or more card is unmarked, all will be marked,
668→     * otherwise, they will be unmarked  */
669→    @NeedsTest("Test that the mark get toggled as expected for a list of selected cards")
670→    private suspend fun toggleMark() {
671→        if (!hasSelectedCards()) {
672→            Timber.i("Not marking cards - nothing selected")
673→            return
674→        }
675→        val cardIds = selectedCardIds
676→        withProgress {
677→            undoableOp {
678→                val noteIds = notesOfCards(cardIds)
679→                // if all notes are marked, remove the mark
680→                // if no notes are marked, add the mark
681→                // if there is a mix, enable the mark on all
682→                val wantMark = !noteIds.all { getNote(it).hasTag("marked") }
683→                if (wantMark) {
684→                    tags.bulkAdd(noteIds, "marked")
685→                } else {
686→                    tags.bulkRemove(noteIds, "marked")
687→                }
688→            }
689→        }
690→    }
